fn isqrt(n: i64) -> i64 = {
    if n < 0 { return 0 };
    if n == 0 { return 0 };
    if n == 1 { return 1 };

    let mut lo = 1;
    let mut hi = n;

    while lo < hi {
        let mid = lo + (hi - lo) / 2;
        let sq = mid * mid;
        if sq <= n {
            lo = mid + 1
        } else {
            hi = mid
        }
    };

    // lo is the first value where lo*lo > n
    // so lo - 1 is the largest value where x*x <= n
    let mut result = lo - 1;
    result
};

